// Clamp rotation to -2 to 2 degrees
const clampedRotation = Math.max(-2, Math.min(2, rotation));

// Map shadow color to glassmorphism preset
const shadowPresetMap: Record<ShadowColor, string> = {
  cyan: neoBrutalism.shadows.presets.glowCyan,
  purple: neoBrutalism.shadows.presets.glowPurple,
  gold: neoBrutalism.shadows.presets.glowGold,
  black: neoBrutalism.shadows.presets.glassMd,
};
const shadowPreset = shadowPresetMap[shadowColor];

// Map shadow color to hover glow color
const hoverColorMap: Record<ShadowColor, string> = {
  cyan: neoBrutalism.shadows.color.cyan,
  purple: neoBrutalism.shadows.color.purple,
  gold: neoBrutalism.shadows.color.gold,
  black: neoBrutalism.shadows.color.dark,
};
const hoverGlowColor = hoverColorMap[shadowColor];

const cardStyle: React.CSSProperties = {
  backgroundColor: colors.panel,
  border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
  borderRadius: borderRadius,
  boxShadow: shadowPreset,
  padding: 0, // Remove default padding, let sections handle it
  transform: `rotate(${clampedRotation}deg)`,
  transition: interactive
    ? `transform ${neoBrutalism.animation.duration.normal} ${neoBrutalism.animation.easing.easeOut}, box-shadow ${neoBrutalism.animation.duration.normal} ${neoBrutalism.animation.easing.easeOut}`
    : '',
  position: 'relative',
  ...style,
};

const headerStyle: React.CSSProperties = {
  padding: padding,
  borderBottom: header && (children || footer) ? `${neoBrutalism.borders.width.default} solid ${colors.border}` : undefined,
  fontFamily: neoBrutalism.typography.subheading.family,
  fontSize: neoBrutalism.typography.subheading.size,
  fontWeight: neoBrutalism.typography.subheading.weight,
  lineHeight: neoBrutalism.typography.subheading.lineHeight,
};

const bodyStyle: React.CSSProperties = {
  padding: padding,
  fontFamily: neoBrutalism.typography.body.family,
  fontSize: neoBrutalism.typography.body.size,
  lineHeight: neoBrutalism.typography.body.lineHeight,
};

const footerStyle: React.CSSProperties = {
  padding: padding,
  borderTop: footer && (header || children) ? `${neoBrutalism.borders.width.default} solid ${colors.border}` : undefined,
  fontSize: neoBrutalism.typography.label.size,
  color: colors.textSecondary,
};

// Interactive hover styles
const interactiveClassName = interactive ? 'card-interactive' : '';
const combinedClassName = `${interactiveClassName} ${className || ''}`.trim();

return (
  <>
    {interactive && (
      <style>{`
        .card-interactive:hover {
          transform: scale(1.03) rotate(${clampedRotation}deg) !important;
          box-shadow: 0 0 20px ${hoverGlowColor} !important;
        }
      `}</style>
    )}

