34:   navBgScrolled: 'rgba(10, 10, 10, 0.85)',
35:   border: neoBrutalism.colors.dark.border,
36:   borderBlack: '#000000',
37:   cyan: neoBrutalism.colors.dark.accentCyan,
38:   linkInactive: neoBrutalism.colors.dark.textSecondary,
39:   linkHover: neoBrutalism.colors.dark.accentCyan,
40:   linkActive: neoBrutalism.colors.dark.accentCyan,
41:   buttonBg: neoBrutalism.colors.dark.accentCyan,
42:   buttonText: '#000000',
43:   buttonShadow: neoBrutalism.shadows.presets.cyanSm,
44:   mobilePanelBg: neoBrutalism.colors.dark.panel,
45:   hamburgerBg: neoBrutalism.colors.dark.panel,
46:   hamburgerIcon: neoBrutalism.colors.dark.textPrimary,
47:   logoGlow: '0 0 10px rgba(0, 229, 255, 0.6)',
48:   accentLineHeight: '2px',
49:   focusRingColor: neoBrutalism.colors.dark.accentCyan,
50: };
51: 
52: /** Slide-out panel animation duration in seconds (300ms) */
53: const PANEL_DURATION = 0.3;
54: 
55: /**
56:  * NavigationBar
57:  *
58:  * Persistent navigation bar with Neo-Brutalism Gaming styling:
59:  * - 4px black bottom border (Requirement 6.1)
60:  * - 2px cyan accent line on active page (Requirement 6.1)
61:  * - Perfect World logo with cyan color and 0 0 10px cyan glow (Requirement 6.2)
62:  * - Backdrop blur and semi-transparent background on scroll (Requirement 6.7)
63:  * - All required links (Home, Download, News, Rankings, Guilds, Territory War, Marketplace, Wiki, Support, Login, Play Now)
64:  * - Sticky positioning with backdrop blur on scroll
65:  * - Keyboard-focusable links with active page highlight
66:  * - Responsive hamburger menu at <768px with slide-out panel (300ms open/close)
67:  *
68:  * Neo-Brutalism Gaming theme — bold, thick borders, offset shadows, cyan accents.
69:  *
70:  * @see Requirements 6.1, 6.2, 6.7
71:  */
72: export function NavigationBar() {
73:   const pathname = usePathname();
74:   const { mode } = useTheme();
75:   const [isScrolled, setIsScrolled] = useState(false);
76:   const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
77: 
78:   // Track scroll position for sticky backdrop blur
79:   useEffect(() => {
80:     const handleScroll = () => {
81:       setIsScrolled(window.scrollY > 0);
82:     };
83: 
84:     window.addEventListener('scroll', handleScroll, { passive: true });
85:     // Check initial scroll position
86:     handleScroll();
87: 
88:     return () => window.removeEventListener('scroll', handleScroll);
89:   }, []);
90: 
91:   // Close mobile menu on route change
92:   useEffect(() => {
93:     setIsMobileMenuOpen(false);
94:   }, [pathname]);
95: 
96:   // Close mobile menu on Escape key
97:   useEffect(() => {
98:     const handleKeyDown = (e: KeyboardEvent) => {
99:       if (e.key === 'Escape' && isMobileMenuOpen) {
100:         setIsMobileMenuOpen(false);
101:       }
102:     };
103: 
104:     document.addEventListener('keydown', handleKeyDown);
105:     return () => document.removeEventListener('keydown', handleKeyDown);
106:   }, [isMobileMenuOpen]);
107: 
108:   // Prevent body scroll when mobile menu is open
109:   useEffect(() => {
110:     if (isMobileMenuOpen) {
111:       document.body.style.overflow = 'hidden';
112:     } else {
113:       document.body.style.overflow = '';
114:     }
115:     return () => {
116:       document.body.style.overflow = '';
117:     };
118:   }, [isMobileMenuOpen]);
119: 
120:   const toggleMobileMenu = useCallback(() => {
121:     setIsMobileMenuOpen((prev) => !prev);
122:   }, []);
123: 
124:   const isActive = (href: string) => {
125:     if (href === '/') return pathname === '/';
126:     return pathname.startsWith(href);
127:   };
128: 
129:   return (
130:     <>
131:       <nav
132:         role="navigation"
133:         aria-label="Main navigation"
134:         className={`fixed top-0 left-0 right-0 z-50 transition-all duration-200 ${
135:           isScrolled
136:             ? 'backdrop-blur-md'
137:             : ''
138:         }`}
139:         style={{
140:           backgroundColor: isScrolled
141:             ? NEO_BRUTALISM_THEME.navBgScrolled
142:             : NEO_BRUTALISM_THEME.navBg,
143:           borderBottom: `${neoBrutalism.borders.width.heavy} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
144:         }}
145:       >
146:         <div className="mx-auto max-w-[1440px] px-4 md:px-6 lg:px-8">
147:           <div className="flex h-16 items-center justify-between">
148:             {/* Logo - Home Link with cyan color and 0 0 10px cyan glow (Requirement 6.2) */}
149:             <Link
150:               href="/"
151:               className="flex items-center gap-2 text-xl font-bold focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
152:               style={{
153:                 color: NEO_BRUTALISM_THEME.cyan,
154:                 fontFamily: neoBrutalism.typography.heading.family,
155:                 textShadow: NEO_BRUTALISM_THEME.logoGlow,
156:                 outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
157:               }}
158:               aria-label="Perfect World - Home"
159:             >
160:               <PerfectWorldLogo color={NEO_BRUTALISM_THEME.cyan} />
161:               <span className="hidden sm:inline">PERFECT WORLD</span>
162:             </Link>
163: 
164:             {/* Desktop Navigation Links */}
165:             <div className="hidden md:flex items-center gap-1">
166:               {NAV_LINKS.map((link) => (
167:                 <NavItem
168:                   key={link.href}
169:                   link={link}
170:                   isActive={isActive(link.href)}
171:                 />
172:               ))}
173:               {AUTH_LINKS.map((link) => (
174:                 <NavItem
175:                   key={link.href}
176:                   link={link}
177:                   isActive={isActive(link.href)}
178:                 />
179:               ))}
180:               {/* Play Now CTA Button with cyan background, 3px black border, 4px cyan shadow (Requirement 6.4) */}
181:               <Link
182:                 href="/play"
183:                 className="ml-2 px-4 py-2 font-bold text-sm uppercase tracking-wide transition-all duration-150 hover:translate-x-[3px] hover:translate-y-[3px] focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2"
184:                 style={{
185:                   backgroundColor: NEO_BRUTALISM_THEME.buttonBg,
186:                   color: NEO_BRUTALISM_THEME.buttonText,
187:                   border: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
188:                   boxShadow: NEO_BRUTALISM_THEME.buttonShadow,
189:                   fontFamily: neoBrutalism.typography.body.family,
190:                   borderRadius: neoBrutalism.borders.radius.none,
191:                   letterSpacing: neoBrutalism.typography.button.letterSpacing,
192:                   outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
193:                 }}
194:               >
195:                 Play Now
196:               </Link>
197:             </div>
198: 
199:             {/* Mobile Hamburger Button with 3px black border (Requirement 6.5) */}
200:             <button
201:               type="button"
202:               className="md:hidden flex items-center justify-center w-10 h-10 focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
203:               onClick={toggleMobileMenu}
204:               aria-expanded={isMobileMenuOpen}
205:               aria-controls="mobile-nav-panel"
206:               aria-label={isMobileMenuOpen ? 'Close navigation menu' : 'Open navigation menu'}
207:               style={{
208:                 border: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
209:                 backgroundColor: NEO_BRUTALISM_THEME.hamburgerBg,
210:                 outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
211:               }}
212:             >
213:               <HamburgerIcon isOpen={isMobileMenuOpen} color={NEO_BRUTALISM_THEME.hamburgerIcon} />
214:             </button>
215:           </div>
216:         </div>
217:       </nav>
218: 
219:       {/* Spacer to prevent content from being hidden behind fixed nav */}
220:       <div className="h-16" aria-hidden="true" />
221: 
222:       {/* Mobile Slide-Out Panel */}
223:       <AnimatePresence>
224:         {isMobileMenuOpen && (
225:           <>
226:             {/* Backdrop overlay */}
227:             <motion.div
228:               initial={{ opacity: 0 }}
229:               animate={{ opacity: 1 }}
230:               exit={{ opacity: 0 }}
231:               transition={{ duration: PANEL_DURATION }}
232:               className="fixed inset-0 z-40 bg-black/60 md:hidden"
233:               onClick={() => setIsMobileMenuOpen(false)}
234:               aria-hidden="true"
235:             />
236: 
237:               {/* Slide-out panel with 4px black left border (Requirement 6.6) */}
238:             <motion.div
239:               id="mobile-nav-panel"
240:               role="dialog"
241:               aria-modal="true"
242:               aria-label="Navigation menu"
243:               initial={{ x: '100%' }}
244:               animate={{ x: 0 }}
245:               exit={{ x: '100%' }}
246:               transition={{ duration: PANEL_DURATION, ease: 'easeInOut' }}
247:               className="fixed top-0 right-0 bottom-0 z-50 w-[280px] max-w-[80vw] overflow-y-auto md:hidden"
248:               style={{
249:                 backgroundColor: NEO_BRUTALISM_THEME.mobilePanelBg,
250:                 borderLeft: `${neoBrutalism.borders.width.heavy} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
251:               }}
252:             >
253:               {/* Panel Header */}
254:               <div
255:                 className="flex items-center justify-between p-4"
256:                 style={{
257:                   borderBottom: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
258:                 }}
259:               >
260:                 <span
261:                   className="text-lg font-bold"
262:                   style={{
263:                     color: NEO_BRUTALISM_THEME.cyan,
264:                     fontFamily: neoBrutalism.typography.heading.family,
265:                     textShadow: NEO_BRUTALISM_THEME.logoGlow,
266:                   }}
267:                 >
268:                   MENU
269:                 </span>
270:                 <button
271:                   type="button"
272:                   onClick={() => setIsMobileMenuOpen(false)}
273:                   className="flex items-center justify-center w-8 h-8 focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
274:                   aria-label="Close navigation menu"
275:                   style={{
276:                     border: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
277:                     backgroundColor: NEO_BRUTALISM_THEME.navBg,
278:                     outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
279:                   }}
280:                 >
281:                   <CloseIcon color={NEO_BRUTALISM_THEME.hamburgerIcon} />
282:                 </button>
283:               </div>
284: 
285:               {/* Mobile Nav Links */}
286:               <div className="flex flex-col p-4 gap-1">
287:                 {NAV_LINKS.map((link) => (
288:                   <MobileNavItem
289:                     key={link.href}
290:                     link={link}
291:                     isActive={isActive(link.href)}
292:                     onClick={() => setIsMobileMenuOpen(false)}
293:                   />
294:                 ))}
295: 
296:                 <div
297:                   className="my-3"
298:                   style={{
299:                     borderTop: `1px solid ${NEO_BRUTALISM_THEME.border}`,
300:                   }}
301:                   aria-hidden="true"
302:                 />
303: 
304:                 {AUTH_LINKS.map((link) => (
305:                   <MobileNavItem
306:                     key={link.href}
307:                     link={link}
308:                     isActive={isActive(link.href)}
309:                     onClick={() => setIsMobileMenuOpen(false)}
310:                   />
311:                 ))}
312: 
313:                 {/* Play Now CTA */}
314:                 <Link
315:                   href="/play"
316:                   onClick={() => setIsMobileMenuOpen(false)}
317:                   className="mt-3 px-4 py-3 font-bold text-center uppercase tracking-wide transition-all duration-150 active:translate-y-[1px] focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2"
318:                   style={{
319:                     backgroundColor: NEO_BRUTALISM_THEME.buttonBg,
320:                     color: NEO_BRUTALISM_THEME.buttonText,
321:                     border: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
322:                     boxShadow: NEO_BRUTALISM_THEME.buttonShadow,
323:                     fontFamily: neoBrutalism.typography.body.family,
324:                     borderRadius: neoBrutalism.borders.radius.none,
325:                     letterSpacing: neoBrutalism.typography.button.letterSpacing,
326:                     outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
327:                   }}
328:                 >
329:                   Play Now
330:                 </Link>
331:               </div>
332:             </motion.div>
333:           </>
334:         )}
335:       </AnimatePresence>
336:     </>
337:   );
338: }
339: 
340: /** Desktop navigation link item with 14px bold text and cyan hover (Requirement 6.3) */
341: function NavItem({
342:   link,
343:   isActive: active,
344: }: {
345:   link: NavLink;
346:   isActive: boolean;
347: }) {
348:   return (
349:     <Link
350:       href={link.href}
351:       className="group relative px-3 py-2 text-sm font-medium transition-colors duration-150 focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
352:       style={{
353:         color: active ? NEO_BRUTALISM_THEME.linkActive : NEO_BRUTALISM_THEME.linkInactive,
354:         fontFamily: neoBrutalism.typography.body.family,
355:         fontWeight: neoBrutalism.typography.body.weightBold,
356:         fontSize: neoBrutalism.typography.button.size,
357:         outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
358:       }}
359:       aria-current={active ? 'page' : undefined}
360:       onMouseEnter={(e) => {
361:         if (!active) {
362:           (e.currentTarget as HTMLElement).style.color = NEO_BRUTALISM_THEME.linkHover;
363:         }
364:       }}
365:       onMouseLeave={(e) => {
366:         if (!active) {
367:           (e.currentTarget as HTMLElement).style.color = NEO_BRUTALISM_THEME.linkInactive;
368:         }
369:       }}
370:     >
371:       {link.label}
372:       {/* 2px cyan accent line on active page (Requirement 6.1) */}
373:       {active && (
374:         <span
375:           className="absolute bottom-0 left-3 right-3"
376:           style={{
377:             height: NEO_BRUTALISM_THEME.accentLineHeight,
378:             backgroundColor: NEO_BRUTALISM_THEME.cyan,
379:           }}
380:           aria-hidden="true"
381:         />
382:       )}
383:     </Link>
384:   );
385: }
386: 
387: /** Mobile navigation link item with keyboard focus indicators (Requirement 6.8) */
388: function MobileNavItem({
389:   link,
390:   isActive: active,
391:   onClick,
392: }: {
393:   link: NavLink;
394:   isActive: boolean;
395:   onClick: () => void;
396: }) {
397:   return (
398:     <Link
399:       href={link.href}
400:       onClick={onClick}
401:       className="px-4 py-3 text-base font-medium transition-colors duration-150 focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
402:       style={{
403:         color: active ? NEO_BRUTALISM_THEME.linkActive : NEO_BRUTALISM_THEME.linkInactive,
404:         backgroundColor: active ? 'rgba(0, 229, 255, 0.08)' : 'transparent',
405:         borderLeft: active
406:           ? `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.cyan}`
407:           : `${neoBrutalism.borders.width.default} solid transparent`,
408:         fontFamily: neoBrutalism.typography.body.family,
409:         fontWeight: neoBrutalism.typography.body.weightBold,
410:         outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
411:       }}
412:       aria-current={active ? 'page' : undefined}
413:     >
414:       {link.label}
415:     </Link>
416:   );
417: }
418: 
419: /** Perfect World Logo SVG */
