# 🎨 Component Examples & Usage Patterns

**Real-world examples of using Perfect World components with Glassmorphism design system.**

---

## 📋 Table of Contents

1. [Badge Examples](#badge-examples)
2. [Button Examples](#button-examples)
3. [Card Examples](#card-examples)
4. [Modal Examples](#modal-examples)
5. [Toast Examples](#toast-examples)
6. [Table Examples](#table-examples)
7. [Custom Patterns](#custom-patterns)
8. [Layout Examples](#layout-examples)

---

## Badge Examples

### Basic Badges

```typescript
import { Badge } from '@perfect-world/ui/components/Badge';

export function BadgeExamples() {
  return (
    <div style={{ display: 'flex', gap: '16px', flexWrap: 'wrap' }}>
      {/* Purple badge with glow */}
      <Badge variant="purple" size="md">
        Season 4
      </Badge>

      {/* Cyan badge with glow */}
      <Badge variant="cyan" size="sm">
        New
      </Badge>

      {/* Gold badge with glow */}
      <Badge variant="gold" size="lg">
        Premium
      </Badge>

      {/* Default badge with glass shadow */}
      <Badge variant="default" size="md">
        Standard
      </Badge>
    </div>
  );
}
```

### Rotated Badges (Playful Asymmetry)

```typescript
export function RotatedBadges() {
  return (
    <div style={{ display: 'flex', gap: '24px' }}>
      <Badge variant="purple" rotation={-2}>
        Limited Time
      </Badge>

      <Badge variant="cyan" rotation={1.5}>
        Hot Deal
      </Badge>

      <Badge variant="gold" rotation={-1}>
        Exclusive
      </Badge>
    </div>
  );
}
```

### Status Badges

```typescript
export function StatusBadges() {
  return (
    <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
      <span>Server Status:</span>
      <Badge variant="cyan" size="sm">Online</Badge>

      <span>Player Count:</span>
      <Badge variant="purple" size="sm">12,543</Badge>

      <span>Event:</span>
      <Badge variant="gold" size="sm">Active</Badge>
    </div>
  );
}
```

---

## Button Examples

### Primary Actions

```typescript
import { Button } from '@perfect-world/ui/components/Button';
import Link from 'next/link';

export function PrimaryActions() {
  return (
    <div style={{ display: 'flex', gap: '16px', flexWrap: 'wrap' }}>
      {/* Primary button with cyan glow */}
      <Link href="/play">
        <Button variant="primary" size="lg">
          Play Now
        </Button>
      </Link>

      {/* Secondary button with cyan glow */}
      <Link href="/download">
        <Button variant="secondary" size="lg">
          Download Launcher
        </Button>
      </Link>

      {/* Tertiary button with purple glow */}
      <Button variant="tertiary" size="md">
        Learn More
      </Button>
    </div>
  );
}
```

### Button Sizes

```typescript
export function ButtonSizes() {
  return (
    <div style={{ display: 'flex', gap: '16px', alignItems: 'center' }}>
      <Button variant="primary" size="sm">Small</Button>
      <Button variant="primary" size="md">Medium</Button>
      <Button variant="primary" size="lg">Large</Button>
    </div>
  );
}
```

### Loading State

```typescript
export function LoadingButton() {
  const [loading, setLoading] = useState(false);

  const handleClick = async () => {
    setLoading(true);
    await someAsyncOperation();
    setLoading(false);
  };

  return (
    <Button 
      variant="primary" 
      size="lg" 
      loading={loading}
      onClick={handleClick}
    >
      {loading ? 'Processing...' : 'Submit'}
    </Button>
  );
}
```

### Full Width Button

```typescript
export function FullWidthButton() {
  return (
    <Button variant="primary" size="lg" fullWidth>
      Continue to Checkout
    </Button>
  );
}
```

---

## Card Examples

### Basic Card

```typescript
import { Card } from '@perfect-world/ui/components/Card';

export function BasicCard() {
  return (
    <Card shadowColor="purple">
      <h3 style={{ margin: '0 0 16px 0' }}>Card Title</h3>
      <p style={{ margin: 0 }}>
        This is a basic card with purple glow shadow effect.
      </p>
    </Card>
  );
}
```

### Interactive Card

```typescript
export function InteractiveCard() {
  return (
    <Card 
      shadowColor="cyan" 
      interactive
      onClick={() => console.log('Card clicked')}
