export function ConfirmationModal() {
  const [isOpen, setIsOpen] = useState(false);

  const handleConfirm = () => {
    // Perform action
    console.log('Confirmed!');
    setIsOpen(false);
  };

  return (
    <>
      <Button variant="tertiary" onClick={() => setIsOpen(true)}>
