```typescript
export function StatCard({ 
  label, 
  value, 
  icon 
}: { 
  label: string; 
  value: string | number; 
  icon?: React.ReactNode;
}) {
  const { colors } = useTheme();

  return (
    <Card shadowColor="cyan" interactive>
      <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
        {icon && (
          <div style={{
            width: '48px',
            height: '48px',
            borderRadius: '50%',
