            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            boxShadow: neoBrutalism.shadows.presets.glowCyan,
          }}>
            {icon}
          </div>
        )}
        <div>
          <div style={{
            fontSize: neoBrutalism.typography.label.size,
            color: colors.textSecondary,
            textTransform: 'uppercase',
            letterSpacing: '0.05em',
          }}>
            {label}
          </div>
          <div style={{
            fontSize: neoBrutalism.typography.heading.desktop,
            fontFamily: neoBrutalism.typography.heading.family,
            color: colors.accentCyan,
            lineHeight: 1,
            marginTop: '4px',
          }}>
            {value}
          </div>
        </div>
      </div>
    </Card>
  );
}
